package main

import (
	"context"
	"database/sql"
	"encoding/json"
	"net/http"
	"strconv"

	"github.com/gorilla/mux"
)

type Order struct {
	ID    int       `json:"id"`
	UserID int       `json:"user_id"`
	Items []Item    `json:"items"`
	Total float64   `json:"total"`
	Status string    `json:"status"`
}

type Item struct {
	ID     int    `json:"id"`
	Name   string `json:"name"`
	Price  float64 `json:"price"`
	Quantity int `json:"quantity"`
}

func getOrderDetails(w http.ResponseWriter, r *http.Request) {
	vars := mux.Vars(r)
	orderIDStr := vars["order_id"]

	orderID, err := strconv.Atoi(orderIDStr)
	if err != nil {
		http.Error(w, "Invalid order ID", http.StatusBadRequest)
		return
	}

	user := getUserFromContext(r.Context())
	if user == nil {
		http.Error(w, "User not authenticated", http.StatusUnauthorized)
		return
	}

	db := getDB()
	defer db.Close()

	order, err := getOrder(db, orderID, user.ID)
	if err != nil {
		if err == sql.ErrNoRows {
			http.Error(w, "Order not found", http.StatusNotFound)
		} else {
			http.Error(w, "Internal server error", http.StatusInternalServerError)
		}
		return
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(order)
}

func getOrder(db *sql.DB, orderID int, userID int) (*Order, error) {
	var order Order
	var items []Item

	err := db.QueryRow(`
		SELECT o.id, o.user_id, SUM(i.price * i.quantity) AS total, o.status
		FROM orders o
		JOIN order_items oi ON o.id = oi.order_id
		JOIN items i ON oi.item_id = i.id
		WHERE o.id = ? AND o.user_id = ?
		GROUP BY o.id, o.user_id, o.status
	`, orderID, userID).Scan(&order.ID, &order.UserID, &order.Total, &order.Status)

	if err != nil {
		return nil, err
	}

	rows, err := db.Query(`
		SELECT i.id, i.name, i.price, oi.quantity
		FROM order_items oi
		JOIN items i ON oi.item_id = i.id
		WHERE oi.order_id = ?
	`, orderID)

	if err != nil {
		return nil, err
	}
	defer rows.Close()

	for rows.Next() {
		var item Item
		err := rows.Scan(&item.ID, &item.Name, &item.Price, &item.Quantity)
		if err != nil {
			return nil, err
		}
		items = append(items, item)
	}

	order.Items = items

	return &order, nil
}

func getUserFromContext(ctx context.Context) *User {
	user, _ := ctx.Value("user").(*User)
	return user
}

func getDB() *sql.DB {
	// Replace with your database connection logic
	return sql.Open("postgres", "your_connection_string")
}

